import base64
import json
import os
import socket
import ssl
import urllib.parse
import urllib.request

MAX_URLS = int(os.getenv("MAX_ENRICH_URLS", "3"))
MAX_RESPONSE_BYTES = int(os.getenv("MAX_RESPONSE_BYTES", "8192"))
REQUEST_TIMEOUT_SECONDS = float(os.getenv("REQUEST_TIMEOUT_SECONDS", "2.0"))
ALLOW_HOSTS = set(filter(None, [h.strip().lower() for h in os.getenv("ALLOW_HOSTS", "").split(",")]))
ALLOW_SCHEMES = {"https"}
FORWARD_HEADER_NAME = "x-enrich-context"
SOURCE_HEADER_NAME = "x-enrich-url"


def _response(status, description, body):
    return {
        "status": str(status),
        "statusDescription": description,
        "headers": {
            "content-type": [{"key": "Content-Type", "value": "application/json"}],
            "cache-control": [{"key": "Cache-Control", "value": "no-store"}],
        },
        "body": json.dumps(body),
    }


def _normalize_headers(headers):
    out = {}
    for k, v in (headers or {}).items():
        lk = k.lower()
        vals = []
        for item in v:
            if "value" in item:
                vals.append(item["value"])
        out[lk] = vals
    return out


def _header_values(headers, name):
    return _normalize_headers(headers).get(name.lower(), [])


def _is_private_ip(host):
    try:
        infos = socket.getaddrinfo(host, None)
    except Exception:
        return True
    for info in infos:
        sockaddr = info[4]
        ip = sockaddr[0]
        try:
            packed = socket.inet_pton(socket.AF_INET, ip)
            first = packed[0]
            second = packed[1]
            if first == 10:
                return True
            if first == 127:
                return True
            if first == 169 and second == 254:
                return True
            if first == 172 and 16 <= second <= 31:
                return True
            if first == 192 and second == 168:
                return True
            if first == 0:
                return True
        except OSError:
            try:
                packed6 = socket.inet_pton(socket.AF_INET6, ip)
                if packed6 == b"\x00" * 16:
                    return True
                if ip == "::1":
                    return True
                if ip.lower().startswith("fc") or ip.lower().startswith("fd"):
                    return True
                if ip.lower().startswith("fe80:"):
                    return True
            except OSError:
                return True
    return False


def _validate_url(url):
    try:
        parsed = urllib.parse.urlparse(url)
    except Exception:
        return False, "invalid_url"

    if parsed.scheme.lower() not in ALLOW_SCHEMES:
        return False, "scheme_not_allowed"

    if not parsed.hostname:
        return False, "missing_host"

    host = parsed.hostname.lower()

    if ALLOW_HOSTS and host not in ALLOW_HOSTS:
        return False, "host_not_allowed"

    if _is_private_ip(host):
        return False, "private_or_unresolvable_host"

    return True, None


def _fetch_url(url):
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "lambda-edge-enrichment/1.0",
            "Accept": "application/json,text/plain;q=0.9,*/*;q=0.1",
        },
        method="GET",
    )

    context = ssl.create_default_context()
    with urllib.request.urlopen(req, timeout=REQUEST_TIMEOUT_SECONDS, context=context) as resp:
        body = resp.read(MAX_RESPONSE_BYTES + 1)
        if len(body) > MAX_RESPONSE_BYTES:
            body = body[:MAX_RESPONSE_BYTES]
        content_type = resp.headers.get("Content-Type", "")
        status = getattr(resp, "status", 200)
        return {
            "url": url,
            "status": status,
            "content_type": content_type,
            "body_b64": base64.b64encode(body).decode("ascii"),
            "truncated": len(body) == MAX_RESPONSE_BYTES,
        }


def lambda_handler(event, context):
    try:
        request = event["Records"][0]["cf"]["request"]
        headers = request.get("headers", {})
        enrich_urls = _header_values(headers, SOURCE_HEADER_NAME)

        if not enrich_urls:
            return request

        enrich_urls = enrich_urls[:MAX_URLS]
        results = []
        errors = []

        for url in enrich_urls:
            ok, reason = _validate_url(url)
            if not ok:
                errors.append({"url": url, "error": reason})
                continue
            try:
                results.append(_fetch_url(url))
            except Exception as exc:
                errors.append({"url": url, "error": exc.__class__.__name__})

        payload = {"results": results}
        if errors:
            payload["errors"] = errors

        encoded = base64.b64encode(json.dumps(payload, separators=(",", ":")).encode("utf-8")).decode("ascii")

        headers[FORWARD_HEADER_NAME] = [{"key": "X-Enrich-Context", "value": encoded}]
        if SOURCE_HEADER_NAME.lower() in headers:
            del headers[SOURCE_HEADER_NAME.lower()]

        request["headers"] = headers
        return request

    except Exception as exc:
        return _response(
            400,
            "Bad Request",
            {"error": "edge_enrichment_failed", "detail": exc.__class__.__name__},
        )